import React from 'react';
import { motion } from 'framer-motion';
import { useInView } from 'react-intersection-observer';
import { 
  FaPython, FaJava, FaReact, FaNodeJs, FaDatabase, 
  FaHtml5, FaCss3Alt, FaJs 
} from 'react-icons/fa';
import { SiCplusplus, SiMongodb, SiMysql, SiNextdotjs } from 'react-icons/si';
import './Skills.css';

const Skills = () => {
  const [ref, inView] = useInView({
    triggerOnce: true,
    threshold: 0.1
  });

  const skillCategories = [
    {
      title: 'Programming Languages',
      skills: [
        { name: 'Python', level: 90, icon: <FaPython /> },
        { name: 'Java', level: 85, icon: <FaJava /> },
        { name: 'C++', level: 88, icon: <SiCplusplus /> },
        { name: 'C', level: 85, icon: <SiCplusplus /> }
      ]
    },
    {
      title: 'Web Development',
      skills: [
        { name: 'HTML/CSS', level: 92, icon: <FaHtml5 /> },
        { name: 'JavaScript', level: 88, icon: <FaJs /> },
        { name: 'React', level: 85, icon: <FaReact /> },
        { name: 'Node.js', level: 82, icon: <FaNodeJs /> },
        { name: 'Next.js', level: 80, icon: <SiNextdotjs /> }
      ]
    },
    {
      title: 'Database & Tools',
      skills: [
        { name: 'MySQL', level: 85, icon: <SiMysql /> },
        { name: 'MongoDB', level: 83, icon: <SiMongodb /> },
        { name: 'DBMS', level: 87, icon: <FaDatabase /> }
      ]
    }
  ];

  return (
    <section className="skills" id="skills">
      <div className="container">
        <motion.div
          ref={ref}
          initial={{ opacity: 0, y: 50 }}
          animate={inView ? { opacity: 1, y: 0 } : {}}
          transition={{ duration: 0.6 }}
        >
          <h2 className="section-title">Technical Skills</h2>

          <div className="skills-grid">
            {skillCategories.map((category, catIndex) => (
              <motion.div
                key={catIndex}
                className="skill-category"
                initial={{ opacity: 0, y: 50, rotateX: -15 }}
                animate={inView ? { opacity: 1, y: 0, rotateX: 0 } : {}}
                transition={{ 
                  delay: catIndex * 0.2, 
                  duration: 0.8,
                  ease: [0.6, -0.05, 0.01, 0.99]
                }}
                whileHover={{ 
                  y: -10, 
                  scale: 1.02,
                  transition: { duration: 0.3 }
                }}
              >
                <h3>{category.title}</h3>
                <div className="skills-list">
                  {category.skills.map((skill, skillIndex) => (
                    <div key={skillIndex} className="skill-item">
                      <div className="skill-header">
                        <div className="skill-name">
                          <span className="skill-icon">{skill.icon}</span>
                          {skill.name}
                        </div>
                        <span className="skill-percentage">{skill.level}%</span>
                      </div>
                      <div className="skill-bar">
                        <motion.div
                          className="skill-progress"
                          initial={{ width: 0, opacity: 0 }}
                          animate={inView ? { width: `${skill.level}%`, opacity: 1 } : {}}
                          transition={{ 
                            delay: catIndex * 0.2 + skillIndex * 0.15, 
                            duration: 1.5,
                            ease: [0.6, 0.01, 0.05, 0.95]
                          }}
                        />
                      </div>
                    </div>
                  ))}
                </div>
              </motion.div>
            ))}
          </div>
        </motion.div>
      </div>
    </section>
  );
};

export default Skills;
